function mergeSort(arr, compare = (a, b) => a - b) {
  if (arr.length <= 1) return arr;

  const mid = Math.floor(arr.length / 2);
  const left = mergeSort(arr.slice(0, mid), compare);
  const right = mergeSort(arr.slice(mid), compare);

  return merge(left, right, compare);
}

function merge(left, right, compare) {
  const result = [];
  let i = 0;
  let j = 0;

  while (i < left.length && j < right.length) {
    if (compare(left[i], right[j]) <= 0) {
      result.push(left[i]);
      i++;
    } else {
      result.push(right[j]);
      j++;
    }
  }

  while (i < left.length) {
    result.push(left[i]);
    i++;
  }

  while (j < right.length) {
    result.push(right[j]);
    j++;
  }

  return result;
}

module.exports = mergeSort;

class TreeNode {
  constructor(val, left = null, right = null) {
    this.val = val;
    this.left = left;
    this.right = right;
  }
}

function levelOrder(root) {
  if (!root) return [];

  const result = [];
  const queue = [root];

  while (queue.length > 0) {
    const levelSize = queue.length;
    const currentLevel = [];

    for (let i = 0; i < levelSize; i++) {
      const node = queue.shift();
      currentLevel.push(node.val);

      if (node.left) queue.push(node.left);
      if (node.right) queue.push(node.right);
    }

    result.push(currentLevel);
  }

  return result;
}

function bfsSearch(graph, start, target) {
  const visited = new Set([start]);
  const queue = [{ node: start, path: [start] }];

  while (queue.length > 0) {
    const { node, path } = queue.shift();
    if (node === target) return path;

    for (const neighbor of (graph.get(node) ?? [])) {
      if (!visited.has(neighbor)) {
        visited.add(neighbor);
        queue.push({ node: neighbor, path: [...path, neighbor] });
      }
    }
  }
  return null;
}

module.exports = { levelOrder, bfsSearch, TreeNode };

class TrieNode {
  constructor() {
    this.children = new Map();
    this.isEndOfWord = false;
    this.count = 0;
  }
}

class Trie {
  constructor() {
    this.root = new TrieNode();
  }

  insert(word) {
    let node = this.root;
    for (const char of word) {
      if (!node.children.has(char)) {
        node.children.set(char, new TrieNode());
      }
      node = node.children.get(char);
      node.count++;
    }
    node.isEndOfWord = true;
  }

  search(word) {
    const node = this._findNode(word);
    return node?.isEndOfWord ?? false;
  }

  autocomplete(prefix, limit = 10) {
    const node = this._findNode(prefix);
    if (!node) return [];

    const results = [];
    this._collectWords(node, prefix, results, limit);
    return results;
  }

  _collectWords(node, current, results, limit) {
    if (results.length >= limit) return;
    if (node.isEndOfWord) results.push(current);

    for (const [char, child] of node.children) {
      this._collectWords(child, current + char, results, limit);
    }
  }

  _findNode(prefix) {
    let node = this.root;
    for (const char of prefix) {
      if (!node.children.has(char)) return null;
      node = node.children.get(char);
    }
    return node;
  }
}

module.exports = { Trie, TrieNode };

function topologicalSort(dependencies) {
  // dependencies: Map<node, Set<dependencies>>
  const inDegree = new Map();
  const adjList = new Map();

  // Initialize all nodes
  for (const [node] of dependencies) {
    if (!inDegree.has(node)) inDegree.set(node, 0);
    if (!adjList.has(node)) adjList.set(node, []);
  }

  // Build adjacency list and compute in-degrees
  for (const [node, deps] of dependencies) {
    for (const dep of deps) {
      if (!adjList.has(dep)) adjList.set(dep, []);
      if (!inDegree.has(dep)) inDegree.set(dep, 0);
      adjList.get(dep).push(node);
      inDegree.set(node, (inDegree.get(node) ?? 0) + 1);
    }
  }

  // Kahn's algorithm
  const queue = [];
  for (const [node, degree] of inDegree) {
    if (degree === 0) queue.push(node);
  }

  const sorted = [];
  while (queue.length > 0) {
    const node = queue.shift();
    sorted.push(node);

    for (const neighbor of adjList.get(node) ?? []) {
      inDegree.set(neighbor, inDegree.get(neighbor) - 1);
      if (inDegree.get(neighbor) === 0) {
        queue.push(neighbor);
      }
    }
  }

  if (sorted.length !== dependencies.size) {
    throw new Error('Cycle detected in dependencies');
  }

  return sorted;
}

module.exports = topologicalSort;

function memoize(fn, keyFn = JSON.stringify) {
  const cache = new Map();
  const meta = { hitCount: 0, missCount: 0, size: 0 };

  function memoized(...args) {
    const key = keyFn(args);
    if (cache.has(key)) {
      meta.hitCount++;
      return cache.get(key);
    }
    meta.missCount++;
    const result = fn.apply(this, args);
    cache.set(key, result);
    meta.size = cache.size;
    return result;
  }

  memoized.clearCache = () => {
    cache.clear();
    meta.hitCount = 0;
    meta.missCount = 0;
    meta.size = 0;
  };

  memoized.stats = () => ({ ...meta, hitRate: meta.hitCount / (meta.hitCount + meta.missCount) || 0 });

  return memoized;
}

// Usage example
const fibonacci = memoize((n) => {
  if (n <= 1) return n;
  return fibonacci(n - 1) + fibonacci(n - 2);
});

const sumRange = memoize((start, end) => {
  let sum = 0;
  for (let i = start; i <= end; i++) sum += i;
  return sum;
}, ([start, end]) => `${start}-${end}`);

module.exports = { memoize, fibonacci, sumRange };

class LRUCache {
  constructor(capacity) {
    this.capacity = capacity;
    this.cache = new Map();
    this.head = new Node(null, null);
    this.tail = new Node(null, null);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key) {
    if (!this.cache.has(key)) return -1;
    const node = this.cache.get(key);
    this._moveToHead(node);
    return node.value;
  }

  put(key, value) {
    if (this.cache.has(key)) {
      const node = this.cache.get(key);
      node.value = value;
      this._moveToHead(node);
      return;
    }

    const newNode = new Node(key, value);
    this.cache.set(key, newNode);
    this._addToHead(newNode);

    if (this.cache.size > this.capacity) {
      const removed = this._removeTail();
      this.cache.delete(removed.key);
    }
  }

  _addToHead(node) {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next.prev = node;
    this.head.next = node;
  }

  _removeNode(node) {
    node.prev.next = node.next;
    node.next.prev = node.prev;
  }

  _moveToHead(node) {
    this._removeNode(node);
    this._addToHead(node);
  }

  _removeTail() {
    const node = this.tail.prev;
    this._removeNode(node);
    return node;
  }
}

class Node {
  constructor(key, value) {
    this.key = key;
    this.value = value;
    this.prev = null;
    this.next = null;
  }
}

module.exports = LRUCache;

function deepClone(obj, seen = new WeakMap()) {
  if (obj === null || typeof obj !== 'object') return obj;

  if (seen.has(obj)) {
    return seen.get(obj);
  }

  if (Array.isArray(obj)) {
    const cloneArr = [];
    seen.set(obj, cloneArr);
    obj.forEach((item, index) => {
      cloneArr[index] = deepClone(item, seen);
    });
    return cloneArr;
  }

  if (obj instanceof Date) return new Date(obj.getTime());
  if (obj instanceof RegExp) return new RegExp(obj.source, obj.flags);
  if (obj instanceof Map) {
    const mapClone = new Map();
    seen.set(obj, mapClone);
    obj.forEach((value, key) => {
      mapClone.set(deepClone(key, seen), deepClone(value, seen));
    });
    return mapClone;
  }
  if (obj instanceof Set) {
    const setClone = new Set();
    seen.set(obj, setClone);
    obj.forEach(value => setClone.add(deepClone(value, seen)));
    return setClone;
  }

  const clone = {};
  seen.set(obj, clone);

  for (const key of Object.keys(obj)) {
    clone[key] = deepClone(obj[key], seen);
  }

  // Preserve prototype chain
  const proto = Object.getPrototypeOf(obj);
  if (proto && proto !== Object.prototype) {
    Object.setPrototypeOf(clone, proto);
  }

  return clone;
}

module.exports = deepClone;

function throttle(fn, delay) {
  let lastCall = 0;
  let timerId = null;

  function throttled(...args) {
    const now = Date.now();
    const remaining = delay - (now - lastCall);

    if (remaining <= 0) {
      if (timerId) {
        clearTimeout(timerId);
        timerId = null;
      }
      lastCall = now;
      fn.apply(this, args);
    } else if (!timerId) {
      timerId = setTimeout(() => {
        lastCall = Date.now();
        timerId = null;
        fn.apply(this, arguments);
      }, remaining);
    }
  }

  throttled.cancel = () => {
    if (timerId) clearTimeout(timerId);
    timerId = null;
    lastCall = 0;
  };

  return throttled;
}

function debounce(fn, delay, options = {}) {
  let timerId = null;
  let lastArgs = null;
  let lastThis = null;
  let maxWait = options.maxWait ?? null;
  let maxTimerId = null;

  function invoke() {
    fn.apply(lastThis, lastArgs);
    timerId = null;
    maxTimerId = null;
  }

  function debounced(...args) {
    lastThis = this;
    lastArgs = args;

    if (timerId) clearTimeout(timerId);
    if (maxWait && maxTimerId) clearTimeout(maxTimerId);

    if (maxWait) {
      maxTimerId = setTimeout(invoke, maxWait);
    }

    timerId = setTimeout(invoke, delay);
  }

  debounced.cancel = () => {
    clearTimeout(timerId);
    clearTimeout(maxTimerId);
    timerId = null;
    maxTimerId = null;
  };

  return debounced;
}

module.exports = { throttle, debounce };
